          }}>
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem'}}>
              <h2 style={{fontSize: '2rem', fontWeight: 'bold', color: '#1e293b', margin: 0}}>👁️ Course Preview</h2>
              <button 
                onClick={() => closeModal('preview')}
                style={{
                  color: '#64748b', 
                  background: 'rgba(255,255,255,0.8)', 
                  border: 'none', 
                  padding: '0.5rem', 
                  cursor: 'pointer', 
                  borderRadius: '12px',
                  boxShadow: '0 4px 15px rgba(0,0,0,0.1)'
                }}
                type="button"
              >
                <X style={{width: '1.5rem', height: '1.5rem'}} />
              </button>
            </div>

            <div style={{textAlign: 'center'}}>
              {/* Video Section */}
              {(selectedCourse.youtubeLink || selectedCourse.videoLink || selectedCourse.dropboxLink || (selectedCourse.videoLinks && selectedCourse.videoLinks.length > 0)) && (
                <div style={{marginBottom: '2rem'}}>
                  <h3 style={{fontSize: '1.2rem', fontWeight: '600', color: '#1e293b', marginBottom: '1rem', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem'}}>
                    🎥 Course Video
                  </h3>
                  {selectedCourse.youtubeLink && (
                    <iframe 
                      src={selectedCourse.youtubeLink.replace('watch?v=', 'embed/')}
                      style={{width: '100%', height: '20rem', borderRadius: '15px', border: 'none', boxShadow: '0 10px 30px rgba(0,0,0,0.2)'}}
                      allowFullScreen
                    />
                  )}
                  {selectedCourse.videoLink && (
                    <video 
                      controls 
                      style={{width: '100%', height: '20rem', borderRadius: '15px', boxShadow: '0 10px 30px rgba(0,0,0,0.2)'}}
                    >
                      <source src={selectedCourse.videoLink} type="video/mp4" />
                      Your browser does not support the video tag.
                    </video>
                  )}
                  {selectedCourse.dropboxLink && (
                    <video 
                      controls 
                      style={{width: '100%', height: '20rem', borderRadius: '15px', boxShadow: '0 10px 30px rgba(0,0,0,0.2)'}}
                    >
                      <source src={selectedCourse.dropboxLink.replace('dropbox.com', 'dl.dropboxusercontent.com').replace('?dl=0', '')} type="video/mp4" />
                      Your browser does not support the video tag.
                    </video>
                  )}
                  {selectedCourse.videoLinks && selectedCourse.videoLinks.length > 0 && (
                    <div style={{marginTop: '1rem'}}>
                      <h4 style={{fontSize: '1rem', fontWeight: '600', color: '#1e293b', marginBottom: '1rem'}}>Additional Videos:</h4>
                      {selectedCourse.videoLinks.map((link, index) => (
                        <div key={index} style={{marginBottom: '1rem'}}>
                          {link.includes('youtube.com') || link.includes('youtu.be') ? (
                            <iframe 
                              src={link.includes('youtu.be') ? 
                                `https://www.youtube.com/embed/${link.split('youtu.be/')[1]}` : 
                                link.replace('youtube.com/watch?v=', 'youtube.com/embed/')}
                              style={{width: '100%', height: '15rem', borderRadius: '15px', border: 'none', boxShadow: '0 10px 30px rgba(0,0,0,0.2)'}}
                              allowFullScreen
                              title={`Video ${index + 1}`}
                            />
                          ) : (
                            <video 
                              controls 
                              style={{width: '100%', height: '15rem', borderRadius: '15px', boxShadow: '0 10px 30px rgba(0,0,0,0.2)'}}
                            >
                              <source src={link.includes('dropbox') ? link.replace('dropbox.com', 'dl.dropboxusercontent.com').replace('?dl=0', '') : link} type="video/mp4" />
                              Your browser does not support the video tag.
                            </video>
                          )}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}

              <img src={selectedCourse.img} alt={selectedCourse.title} style={{width: '100%', height: '15rem', objectFit: 'cover', borderRadius: '20px', marginBottom: '1.5rem', boxShadow: '0 15px 35px rgba(0,0,0,0.15)'}} />
              <h3 style={{fontSize: '1.8rem', fontWeight: 'bold', color: '#1e293b', marginBottom: '1rem'}}>{selectedCourse.title}</h3>
              <p style={{color: '#64748b', marginBottom: '1.5rem', lineHeight: '1.6', fontSize: '1.1rem'}}>{selectedCourse.desc}</p>

              <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1.5rem', textAlign: 'left'}}>
                <div style={{background: 'linear-gradient(135deg, rgba(22,163,74,0.1) 0%, rgba(22,163,74,0.05) 100%)', padding: '1.5rem', borderRadius: '15px', border: '1px solid rgba(22,163,74,0.2)'}}>
                  <p style={{color: '#64748b', fontSize: '0.9rem', marginBottom: '0.5rem', fontWeight: '500'}}>Price</p>
                  <p style={{color: '#16a34a', fontWeight: 'bold', fontSize: '1.5rem'}}>₹{selectedCourse.price}</p>
                </div>
                <div style={{background: 'linear-gradient(135deg, rgba(59,130,246,0.1) 0%, rgba(59,130,246,0.05) 100%)', padding: '1.5rem', borderRadius: '15px', border: '1px solid rgba(59,130,246,0.2)'}}>
                  <p style={{color: '#64748b', fontSize: '0.9rem', marginBottom: '0.5rem', fontWeight: '500'}}>Students</p>
                  <p style={{color: '#1e293b', fontWeight: 'bold', fontSize: '1.5rem'}}>{selectedCourse.enrolled}</p>
                </div>
                <div style={{background: 'linear-gradient(135deg, rgba(147,51,234,0.1) 0%, rgba(147,51,234,0.05) 100%)', padding: '1.5rem', borderRadius: '15px', border: '1px solid rgba(147,51,234,0.2)'}}>
                  <p style={{color: '#64748b', fontSize: '0.9rem', marginBottom: '0.5rem', fontWeight: '500'}}>Level</p>
                  <p style={{color: '#1e293b', fontWeight: 'bold', fontSize: '1.2rem'}}>{selectedCourse.level}</p>
                </div>
                <div style={{background: 'linear-gradient(135deg, rgba(217,119,6,0.1) 0%, rgba(217,119,6,0.05) 100%)', padding: '1.5rem', borderRadius: '15px', border: '1px solid rgba(217,119,6,0.2)'}}>
                  <p style={{color: '#64748b', fontSize: '0.9rem', marginBottom: '0.5rem', fontWeight: '500'}}>Duration</p>
                  <p style={{color: '#1e293b', fontWeight: 'bold', fontSize: '1.2rem'}}>{selectedCourse.time}</p>
                </div>
              </div>

              <div style={{display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.75rem', marginBottom: '1.5rem'}}>
                <Star style={{width: '1.5rem', height: '1.5rem', color: '#d97706'}} />
                <span style={{fontSize: '1.3rem', fontWeight: 'bold', color: '#1e293b'}}>{selectedCourse.rating}</span>
                <span style={{color: '#64748b', fontSize: '1.1rem'}}>({selectedCourse.enrolled} reviews)</span>
              </div>

              <div style={{
                background: 'linear-gradient(45deg, #667eea, #764ba2)', 
                color: 'white', 
                padding: '0.75rem 1.5rem', 
                borderRadius: '25px', 
                display: 'inline-block', 
                fontSize: '1rem', 
                fontWeight: '600',
                boxShadow: '0 8px 25px rgba(102,126,234,0.3)'
              }}>
                {selectedCourse.cat.charAt(0).toUpperCase() + selectedCourse.cat.slice(1)}
              </div>

              {/* Exit Button */}
              <div style={{marginTop: '2rem'}}>
                <button 
                  onClick={() => closeModal('preview')}
                  style={{
                    background: 'linear-gradient(45deg, #ff6b6b, #ee5a24)', 
                    color: 'white', 
                    padding: '1rem 2rem', 
                    borderRadius: '25px', 
                    border: 'none', 
                    cursor: 'pointer', 
                    fontSize: '1.1rem', 
                    fontWeight: '600',
                    boxShadow: '0 8px 25px rgba(255,107,107,0.3)',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '0.5rem',
                    margin: '0 auto'
                  }}
                >
                  <X style={{width: '1.25rem', height: '1.25rem'}} />
                  Exit Preview
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default InstructorDashboard;
